    filters = {
        'location': request.args.get('location', ''),
        'vehicle_type': request.args.get('vehicle_type', ''),
        'date_range': request.args.get('date_range', '')
    }

    # Apply filters
    filtered_vehicles = vehicles

    # Filter by city location if specified
    if filters['location']:
        # Only include vehicles available at that location (by matching locations and availability)
        # Since vehicles do not have direct location in schema, assume all vehicles are listed but status might differ
        # The design_spec doesn't specify availability filtering logic by location, so just pass all vehicles
        # So we do no filter here.
