@app.route('/booking/<int:vehicle_id>', methods=['GET', 'POST'])
def booking_page(vehicle_id):
    vehicles = read_vehicles()
    vehicle = next((v for v in vehicles if v['vehicle_id'] == vehicle_id), None)
    locations_data = read_locations()
    locations = sorted({loc['city'] for loc in locations_data})

    rental_data = {'pickup_location': '', 'dropoff_location': '', 'pickup_date': '', 'dropoff_date': ''}
    total_price = None

    if request.method == 'POST':
        # Booking form post for price calculation or proceed
        pickup_location = request.form.get('pickup_location', '').strip()
        dropoff_location = request.form.get('dropoff_location', '').strip()
        pickup_date = request.form.get('pickup_date', '').strip()
        dropoff_date = request.form.get('dropoff_date', '').strip()

        rental_data.update({
            'pickup_location': pickup_location,
            'dropoff_location': dropoff_location,
            'pickup_date': pickup_date,
            'dropoff_date': dropoff_date
        })

        # Validate input dates
        try:
            p_date = datetime.strptime(pickup_date, '%Y-%m-%d')
            d_date = datetime.strptime(dropoff_date, '%Y-%m-%d')
            if p_date > d_date:
                total_price = None
            else:
                days = (d_date - p_date).days + 1
                total_price = round(days * vehicle['daily_rate'], 2)
        except Exception:
            total_price = None

        # Check if user clicked proceed to insurance (hidden field or button name)
        if 'proceed_to_insurance' in request.form and total_price is not None:
            # Create a rental and reservation record to get reservation_id
            # But since no customer info or ID is provided in specification, we cannot create customer or rental for real
            # So we create dummy rental_id, reservation_id for next pages

            rentals = read_rentals()
            reservations = read_reservations()

            max_rental_id = max((r['rental_id'] for r in rentals), default=0)
            max_reservation_id = max((res['reservation_id'] for res in reservations), default=0)

            new_rental_id = max_rental_id + 1
            new_reservation_id = max_reservation_id + 1

            # We must create a rental entry with status "Pending"

            # Use dummy customer_id = 0 since no customer info is available or user login
            dummy_customer_id = 0

            try:
                pickup_dt_obj = datetime.strptime(pickup_date, '%Y-%m-%d').date()
                dropoff_dt_obj = datetime.strptime(dropoff_date, '%Y-%m-%d').date()
            except Exception:
                pickup_dt_obj = None
                dropoff_dt_obj = None

            rental_record = {
                'rental_id': new_rental_id,
                'vehicle_id': vehicle_id,
                'customer_id': dummy_customer_id,
                'pickup_date': pickup_date,
                'dropoff_date': dropoff_date,
                'pickup_location': pickup_location,
                'dropoff_location': dropoff_location,
                'total_price': total_price,
                'status': 'Pending'
            }
            rentals.append(rental_record)
            write_rentals(rentals)

            reservation_record = {
                'reservation_id': new_reservation_id,
                'rental_id': new_rental_id,
                'vehicle_id': vehicle_id,
                'customer_id': dummy_customer_id,
                'status': 'Pending',
                'insurance_id': 0,
                'special_requests': ''
            }
            reservations.append(reservation_record)
            write_reservations(reservations)

            return redirect(url_for('insurance_options', reservation_id=new_reservation_id))

    return render_template('booking.html', vehicle=vehicle, locations=locations, rental_data=rental_data, total_price=total_price)


@app.route('/insurance/<int:reservation_id>', methods=['GET', 'POST'])
def insurance_options(reservation_id):
    insurance_plans = read_insurances()
    reservations = read_reservations()

    reservation = next((res for res in reservations if res['reservation_id'] == reservation_id), None)
    if not reservation:
        # Invalid reservation id
        return redirect(url_for('dashboard'))

    selected_plan = None

    if request.method == 'POST':
        # Get selected insurance plan id from form
        selected_id = request.form.get('insurance_id')
        try:
            selected_insurance_id = int(selected_id)
        except Exception:
            selected_insurance_id = None

        if selected_insurance_id is not None:
            plan = next((ip for ip in insurance_plans if ip['insurance_id'] == selected_insurance_id), None)
            if plan:
                selected_plan = plan
                # Update reservation insurance_id and status Confirmed
                reservation['insurance_id'] = selected_insurance_id
                reservation['status'] = 'Confirmed'
                # Persist update
                write_reservations(reservations)
                # Redirect to reservation management after confirmation
                return redirect(url_for('reservation_management'))

    if reservation['insurance_id'] != 0:
        selected_plan = next((ip for ip in insurance_plans if ip['insurance_id'] == reservation['insurance_id']), None)

    return render_template('insurance.html', insurance_plans=insurance_plans, selected_plan=selected_plan, reservation_id=reservation_id)


