    if auction is None:
        # No auction found, handle with empty or error page fallback (render empty page or 404)
        auction = {
            'auction_id': auction_id,
            'item_name': '',
            'description': '',
            'current_bid': 0.0,
            'status': ''
        }

    # bid_history: list of dict with bid_id, bidder_name, bid_amount, bid_timestamp
    # We get bid_history entries matching auction_id
    bid_hist_filtered = [
        {
            'bid_id': bh['history_id'],
