@app.route('/auction/<int:auction_id>/place_bid', methods=['GET', 'POST'])
def place_bid(auction_id):
    auctions = read_auctions()

    auction = next((a for a in auctions if a['auction_id'] == auction_id), None)
    if auction is None:
        return redirect(url_for('auction_catalog'))

    errors = {}
    auction_name = auction['item_name']
    minimum_bid = max(auction['current_bid'], auction['starting_bid']) if auction['current_bid'] >= auction['starting_bid'] else auction['starting_bid']

    if request.method == 'POST':
        bidder_name = request.form.get('bidder_name', '').strip()
        bid_amount_str = request.form.get('bid_amount', '').strip()
        bid_amount = 0.0
        # Validate form data
        if not bidder_name:
            errors['bidder_name'] = 'Bidder name is required.'
        try:
            bid_amount = float(bid_amount_str)
            if bid_amount < minimum_bid:
                errors['bid_amount'] = f'Bid amount must be at least {minimum_bid:.2f}.'
        except ValueError:
            errors['bid_amount'] = 'Invalid bid amount.'

        if not errors:
            # Record the bid: add to bids.txt and add to bid_history.txt and update auctions.txt current_bid
            bids = read_bids()
            bid_history = read_bid_history()

            new_bid_id = max((bid['bid_id'] for bid in bids), default=0) + 1
            new_history_id = max((bh['history_id'] for bh in bid_history), default=0) + 1

            from datetime import datetime
            now_str = datetime.now().strftime('%Y-%m-%d %H:%M')

            # Append new bid to bids.txt
            bid_line = f"{new_bid_id}|{auction_id}|{bidder_name}|{bid_amount:.2f}|{now_str}\n"
            with open(BIDS_FILE, 'a', encoding='utf-8') as f:
                f.write(bid_line)

            # Append new bid to bid_history.txt
            history_line = f"{new_history_id}|{auction_id}|{auction_name}|{bidder_name}|{bid_amount:.2f}|{now_str}\n"
            with open(BID_HISTORY_FILE, 'a', encoding='utf-8') as f:
                f.write(history_line)

            # Update auctions.txt with new current_bid
            # Read all auctions and overwrite with updated current_bid on matching auction
            auctions_full = read_auctions()
            with open(AUCTIONS_FILE, 'w', encoding='utf-8') as f:
                for a in auctions_full:
                    if a['auction_id'] == auction_id:
                        a['current_bid'] = bid_amount
                    line = f"{a['auction_id']}|{a['item_name']}|{a['description']}|{a['category']}|{a['starting_bid']:.2f}|{a['current_bid']:.2f}|{a['end_time']}|{a['status']}|{a['image_url']}\n"
                    f.write(line)

            return redirect(url_for('auction_details', auction_id=auction_id))

        # If errors, render with errors
        return render_template('place_bid.html', auction_name=auction_name, minimum_bid=minimum_bid, bidder_name=bidder_name, bid_amount=bid_amount, errors=errors)

    # GET request
    return render_template('place_bid.html', auction_name=auction_name, minimum_bid=minimum_bid)


