@app.route('/status')
def auction_status():
    auctions = read_auctions()

    # auctions context: auction_id, item_name, status, time_remaining, current_bid
    # Calculate time_remaining as difference between end_time and now in a string format
    from datetime import datetime
    status_list = []
    now = datetime.now()

    for a in auctions:
        time_remaining = ''
        try:
            end_dt = datetime.strptime(a['end_time'], '%Y-%m-%d %H:%M')
            delta = end_dt - now
            if delta.total_seconds() > 0:
                days = delta.days
                hours, rem = divmod(delta.seconds, 3600)
                minutes = rem // 60
                parts = []
                if days > 0:
                    parts.append(f"{days}d")
                if hours > 0:
                    parts.append(f"{hours}h")
                if minutes > 0:
                    parts.append(f"{minutes}m")
                time_remaining = ' '.join(parts) if parts else 'less than a minute'
            else:
                time_remaining = 'Ended'
        except Exception:
            time_remaining = 'Unknown'

        status_list.append({
            'auction_id': a['auction_id'],
            'item_name': a['item_name'],
            'status': a['status'],
            'time_remaining': time_remaining,
            'current_bid': a['current_bid']
        })

    return render_template('status.html', auctions=status_list)


if __name__ == '__main__':
    app.run(debug=True, port=5000)

