from flask import Flask, render_template, request, redirect, url_for, abort
import os
from datetime import datetime

app = Flask(__name__)

DATA_DIR = 'data'

# Helper functions for reading and writing data files

def read_pipe_delimited_file(filename):
    filepath = os.path.join(DATA_DIR, filename)
    data = []
    if not os.path.exists(filepath):
        return data
    with open(filepath, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if line:
                data.append(line.split('|'))
    return data


def write_pipe_delimited_file(filename, rows):
    filepath = os.path.join(DATA_DIR, filename)
    with open(filepath, 'w', encoding='utf-8') as f:
        for row in rows:
            f.write('|'.join(str(item) for item in row) + '\n')


# Load users
# users.txt: user_id|username|fullname|email
# Not specified in design, but from context user data read for fullname and email update

def load_users():
    rows = read_pipe_delimited_file('users.txt')
    users = {}
    for row in rows:
        if len(row) >= 4:
            user_id, username, fullname, email = row[:4]
            users[username] = {
                'user_id': user_id,
                'username': username,
                'fullname': fullname,
                'email': email
            }
    return users


def save_users(users):
    rows = []
    for u in users.values():
        rows.append([u['user_id'], u['username'], u['fullname'], u['email']])
    write_pipe_delimited_file('users.txt', rows)


# Load courses
# courses.txt: course_id|title|description|category|level|duration|status

def load_courses():
    rows = read_pipe_delimited_file('courses.txt')
    courses = {}
    for row in rows:
        if len(row) >= 7:
            course_id, title, description, category, level, duration, status = row[:7]
            courses[course_id] = {
                'course_id': course_id,
                'title': title,
                'description': description,
                'category': category,
                'level': level,
                'duration': duration,
                'status': status
            }
    return courses


# Load enrollments
# enrollments.txt: enrollment_id|username|course_id|enroll_date|progress|status

def load_enrollments():
    rows = read_pipe_delimited_file('enrollments.txt')
    enrollments = []
    for row in rows:
        if len(row) >= 6:
            enrollment_id, username, course_id, enroll_date, progress, status = row[:6]
            enrollments.append({
                'enrollment_id': enrollment_id,
                'username': username,
                'course_id': course_id,
                'enroll_date': enroll_date,
                'progress': int(progress),
                'status': status
            })
    return enrollments


def save_enrollments(enrollments):
    rows = []
    for e in enrollments:
        rows.append([
            e['enrollment_id'],
            e['username'],
            e['course_id'],
            e['enroll_date'],
            str(e['progress']),
            e['status']
        ])
    write_pipe_delimited_file('enrollments.txt', rows)


# Load assignments
# assignments.txt: assignment_id|course_id|title|description|due_date|max_points

def load_assignments():
    rows = read_pipe_delimited_file('assignments.txt')
    assignments = []
    for row in rows:
        if len(row) >= 6:
            assignment_id, course_id, title, description, due_date, max_points = row[:6]
            assignments.append({
                'assignment_id': assignment_id,
                'course_id': course_id,
                'title': title,
                'description': description,
                'due_date': due_date,
                'max_points': int(max_points)
            })
    return assignments


# Load submissions
# submissions.txt: submission_id|assignment_id|username|submission_text|submit_date|grade|feedback

def load_submissions():
    rows = read_pipe_delimited_file('submissions.txt')
    submissions = []
    for row in rows:
        if len(row) >= 7:
            submission_id, assignment_id, username, submission_text, submit_date, grade, feedback = row[:7]
            submissions.append({
                'submission_id': submission_id,
                'assignment_id': assignment_id,
                'username': username,
                'submission_text': submission_text,
                'submit_date': submit_date,
                'grade': grade if grade else None,
                'feedback': feedback if feedback else None
            })
    return submissions


def save_submissions(submissions):
    rows = []
    for s in submissions:
        rows.append([
            s['submission_id'],
            s['assignment_id'],
            s['username'],
            s['submission_text'],
            s['submit_date'],
            s['grade'] if s['grade'] is not None else '',
            s['feedback'] if s['feedback'] is not None else ''
        ])
    write_pipe_delimited_file('submissions.txt', rows)


# Load certificates
# certificates.txt: certificate_id|username|course_id|issue_date

def load_certificates():
    rows = read_pipe_delimited_file('certificates.txt')
    certificates = []
    for row in rows:
        if len(row) >= 4:
            certificate_id, username, course_id, issue_date = row[:4]
            certificates.append({
                'certificate_id': certificate_id,
                'username': username,
                'course_id': course_id,
                'issue_date': issue_date
            })
    return certificates


def save_certificates(certificates):
    rows = []
    for c in certificates:
        rows.append([
            c['certificate_id'],
            c['username'],
            c['course_id'],
            c['issue_date']
        ])
    write_pipe_delimited_file('certificates.txt', rows)


# Helper functions

def generate_new_enrollment_id(enrollments):
    max_id = 0
    for e in enrollments:
        try:
            eid = int(e['enrollment_id'])
        except:
            eid = 0
        if eid > max_id:
            max_id = eid
    return str(max_id + 1)


def generate_new_submission_id(submissions):
    max_id = 0
    for s in submissions:
        try:
            sid = int(s['submission_id'])
        except:
            sid = 0
        if sid > max_id:
            max_id = sid
    return str(max_id + 1)


def generate_new_certificate_id(certificates):
    max_id = 0
    for c in certificates:
        try:
            cid = int(c['certificate_id'])
        except:
            cid = 0
        if cid > max_id:
            max_id = cid
    return str(max_id + 1)


def get_enrollment(username, course_id, enrollments):
    for e in enrollments:
        if e['username'] == username and e['course_id'] == course_id:
            return e
    return None


