@app.route('/catalog/course/<course_id>', methods=['GET', 'POST'])
def course_details(course_id):
    username = LOGGED_IN_USERNAME
    users = load_users()
    user = users.get(username)
    if not user:
        abort(404)

    courses = load_courses()
    course = courses.get(course_id)
    if not course:
        abort(404)

    enrollments = load_enrollments()
    enrollment = get_enrollment(username, course_id, enrollments)
    enrolled = enrollment is not None

    if request.method == 'POST':
        if not enrolled:
            # Enroll new user
            new_id = generate_new_enrollment_id(enrollments)
            enroll_date = datetime.now().strftime('%Y-%m-%d')
            enrollments.append({
                'enrollment_id': new_id,
                'username': username,
                'course_id': course_id,
                'enroll_date': enroll_date,
                'progress': 0,
                'status': 'In Progress'
            })
            save_enrollments(enrollments)
            enrolled = True
        else:
            # If enrolled and progress < 100%, setting progress to 100% triggers certificate
            if enrollment['progress'] < 100:
                enrollment['progress'] = 100
                enrollment['status'] = 'Completed'

                # Save enrollment update
                save_enrollments(enrollments)

                # Check if certificate exists
                certificates = load_certificates()
                cert_exists = any(c['username'] == username and c['course_id'] == course_id for c in certificates)
                if not cert_exists:
                    cert_id = generate_new_certificate_id(certificates)
                    issue_date = datetime.now().strftime('%Y-%m-%d')
                    certificates.append({
                        'certificate_id': cert_id,
                        'username': username,
                        'course_id': course_id,
                        'issue_date': issue_date
                    })
                    save_certificates(certificates)

    return render_template('course_details.html', course=course, enrolled=enrolled)


