app = Flask(__name__)

DATA_DIR = 'data'

# Helper functions for reading and writing data files

def read_pipe_delimited_file(filename):
    filepath = os.path.join(DATA_DIR, filename)
    data = []
    if not os.path.exists(filepath):
        return data
    with open(filepath, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if line:
                data.append(line.split('|'))
    return data


def write_pipe_delimited_file(filename, rows):
    filepath = os.path.join(DATA_DIR, filename)
    with open(filepath, 'w', encoding='utf-8') as f:
        for row in rows:
            f.write('|'.join(str(item) for item in row) + '\n')


# Load users
# users.txt: user_id|username|fullname|email
# Not specified in design, but from context user data read for fullname and email update

def load_users():
    rows = read_pipe_delimited_file('users.txt')
    users = {}
    for row in rows:
        if len(row) >= 4:
            user_id, username, fullname, email = row[:4]
            users[username] = {
                'user_id': user_id,
                'username': username,
                'fullname': fullname,
                'email': email
            }
    return users


def save_users(users):
    rows = []
    for u in users.values():
        rows.append([u['user_id'], u['username'], u['fullname'], u['email']])
    write_pipe_delimited_file('users.txt', rows)


# Load courses
# courses.txt: course_id|title|description|category|level|duration|status

def load_courses():
    rows = read_pipe_delimited_file('courses.txt')
    courses = {}
    for row in rows:
        if len(row) >= 7:
            course_id, title, description, category, level, duration, status = row[:7]
            courses[course_id] = {
                'course_id': course_id,
                'title': title,
                'description': description,
                'category': category,
                'level': level,
                'duration': duration,
                'status': status
            }
    return courses


# Load enrollments
# enrollments.txt: enrollment_id|username|course_id|enroll_date|progress|status

def load_enrollments():
    rows = read_pipe_delimited_file('enrollments.txt')
    enrollments = []
    for row in rows:
        if len(row) >= 6:
            enrollment_id, username, course_id, enroll_date, progress, status = row[:6]
            enrollments.append({
                'enrollment_id': enrollment_id,
                'username': username,
                'course_id': course_id,
                'enroll_date': enroll_date,
                'progress': int(progress),
                'status': status
            })
    return enrollments


def save_enrollments(enrollments):
    rows = []
    for e in enrollments:
        rows.append([
            e['enrollment_id'],
            e['username'],
            e['course_id'],
            e['enroll_date'],
            str(e['progress']),
