# Load submissions
# submissions.txt: submission_id|assignment_id|username|submission_text|submit_date|grade|feedback

def load_submissions():
    rows = read_pipe_delimited_file('submissions.txt')
    submissions = []
    for row in rows:
        if len(row) >= 7:
            submission_id, assignment_id, username, submission_text, submit_date, grade, feedback = row[:7]
