# Helper functions

def generate_new_enrollment_id(enrollments):
    max_id = 0
    for e in enrollments:
        try:
            eid = int(e['enrollment_id'])
        except:
            eid = 0
        if eid > max_id:
            max_id = eid
    return str(max_id + 1)


def generate_new_submission_id(submissions):
    max_id = 0
    for s in submissions:
        try:
            sid = int(s['submission_id'])
        except:
            sid = 0
        if sid > max_id:
            max_id = sid
    return str(max_id + 1)


def generate_new_certificate_id(certificates):
    max_id = 0
    for c in certificates:
        try:
            cid = int(c['certificate_id'])
        except:
            cid = 0
        if cid > max_id:
            max_id = cid
    return str(max_id + 1)


def get_enrollment(username, course_id, enrollments):
    for e in enrollments:
        if e['username'] == username and e['course_id'] == course_id:
            return e
    return None


