from flask import Flask, render_template, request, redirect, url_for
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'
LOCATIONS_FILE = os.path.join(DATA_DIR, 'locations.txt')
CURRENT_WEATHER_FILE = os.path.join(DATA_DIR, 'current_weather.txt')
SAVED_LOCATIONS_FILE = os.path.join(DATA_DIR, 'saved_locations.txt')
FORECASTS_FILE = os.path.join(DATA_DIR, 'forecasts.txt')
ALERTS_FILE = os.path.join(DATA_DIR, 'alerts.txt')
AIR_QUALITY_FILE = os.path.join(DATA_DIR, 'air_quality.txt')

# Utility functions to load data

def load_locations():
    locations = []
    try:
        with open(LOCATIONS_FILE, 'r') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) >= 6:
                    location = {
                        'location_id': int(parts[0]),
                        'location_name': parts[1],
                        'latitude': float(parts[2]),
                        'longitude': float(parts[3]),
                        'country': parts[4],
                        'timezone': parts[5]
                    }
                    locations.append(location)
    except FileNotFoundError:
        pass
    return locations


def load_current_weather():
    current_weather = []
    try:
        with open(CURRENT_WEATHER_FILE, 'r') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) >= 7:
                    cw = {
                        'location_id': int(parts[0]),
                        'location_name': parts[1],
                        'temperature': float(parts[2]),
                        'condition': parts[3],
                        'humidity': int(parts[4]),
                        'wind_speed': float(parts[5]),
                        'last_updated': parts[6]
                    }
                    current_weather.append(cw)
    except FileNotFoundError:
        pass
    return current_weather


def load_saved_locations():
    saved_locations = []
    try:
        with open(SAVED_LOCATIONS_FILE, 'r') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) >= 5:
                    saved = {
                        'saved_id': int(parts[0]),
                        'user_id': int(parts[1]),
                        'location_id': int(parts[2]),
                        'location_name': parts[3],
                        'is_default': parts[4] == '1'
                    }
                    saved_locations.append(saved)
    except FileNotFoundError:
        pass
    return saved_locations


def load_forecasts():
    forecasts = []
    try:
        with open(FORECASTS_FILE, 'r') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) >= 8:
                    forecast = {
                        'forecast_id': int(parts[0]),
                        'location_id': int(parts[1]),
                        'date': parts[2],
                        'high_temp': float(parts[3]),
                        'low_temp': float(parts[4]),
                        'condition': parts[5],
                        'precipitation': int(parts[6]),
                        'humidity': int(parts[7])
                    }
                    forecasts.append(forecast)
    except FileNotFoundError:
        pass
    return forecasts


def load_alerts():
    alerts = []
    try:
        with open(ALERTS_FILE, 'r') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) >= 8:
                    alert = {
                        'alert_id': int(parts[0]),
                        'location_id': int(parts[1]),
                        'alert_type': parts[2],
                        'severity': parts[3],
                        'description': parts[4],
                        'start_time': parts[5],
                        'end_time': parts[6],
                        'is_acknowledged': parts[7] == '1'
                    }
                    alerts.append(alert)
    except FileNotFoundError:
        pass
    return alerts


def load_air_quality():
    air_quality_data = []
    try:
        with open(AIR_QUALITY_FILE, 'r') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) >= 8:
                    aqi = {
                        'aqi_id': int(parts[0]),
                        'location_id': int(parts[1]),
                        'aqi_index': int(parts[2]),
                        'pm25': float(parts[3]),
                        'pm10': float(parts[4]),
                        'no2': float(parts[5]),
                        'o3': float(parts[6]),
                        'last_updated': parts[7]
                    }
                    air_quality_data.append(aqi)
    except FileNotFoundError:
        pass
    return air_quality_data


def get_default_location_id(saved_locations):
    for loc in saved_locations:
        if loc.get('is_default'):
            return loc['location_id']
    if saved_locations:
        return saved_locations[0]['location_id']
    return None


def merge_current_weather_for_saved_locations(saved_locations, current_weather):
    weather_map = {cw['location_id']: cw for cw in current_weather}
    enriched_locations = []
    for saved in saved_locations:
        loc_id = saved['location_id']
        cw = weather_map.get(loc_id)
        enriched_locations.append({
            'saved_id': saved['saved_id'],
            'location_id': loc_id,
            'location_name': saved['location_name'],
            'is_default': saved['is_default'],
            'current_temperature': cw['temperature'] if cw else None,
            'current_condition': cw['condition'] if cw else None
        })
    return enriched_locations


def get_location_by_id(locations, location_id):
    for loc in locations:
        if loc['location_id'] == location_id:
            return loc
    return None


@app.route('/')
@app.route('/dashboard')
def dashboard():
    saved_locations = load_saved_locations()
    current_weather = load_current_weather()
    enriched_locations = merge_current_weather_for_saved_locations(saved_locations, current_weather)

    default_location_id = get_default_location_id(saved_locations)

    current_weather_map = {cw['location_id']: cw for cw in current_weather}
    selected_location_id = request.args.get('location_id', default_location_id, type=int)

    cw = current_weather_map.get(selected_location_id)
    if not cw:
        cw = {
            'location_id': None,
            'location_name': '',
            'temperature': None,
            'condition': '',
            'humidity': None,
            'wind_speed': None,
            'last_updated': ''
        }

    return render_template('dashboard.html', current_weather=cw)


@app.route('/location_search')
def location_search():
    search_query = request.args.get('query', '')
    locations = load_locations()
    search_results = []
    if search_query:
        query_lower = search_query.lower()
        search_results = [loc for loc in locations if query_lower in loc['location_name'].lower()]

    saved_locations = merge_current_weather_for_saved_locations(load_saved_locations(), load_current_weather())

    return render_template('location_search.html', search_query=search_query, search_results=search_results, saved_locations=saved_locations)


@app.route('/current_weather/<int:location_id>')
def current_weather(location_id):
    locations = load_locations()
    current_weather_list = load_current_weather()
    loc = get_location_by_id(locations, location_id)
    cw = next((cw for cw in current_weather_list if cw['location_id'] == location_id), None)

    if not loc:
        return f"Location with id {location_id} not found.", 404
    if not cw:
        cw = {
            'location_id': loc['location_id'],
            'location_name': loc['location_name'],
            'temperature': None,
            'condition': '',
            'humidity': None,
            'wind_speed': None,
            'last_updated': ''
        }

    return render_template('current_weather.html', location_name=loc['location_name'], temperature=cw['temperature'], condition=cw['condition'], humidity=cw['humidity'], wind_speed=cw['wind_speed'])


